def access_patient_record(user_id: str, user_role: str, patient_id: str):
    '''
    Implement a function named 'access_patient_record' that allows healthcare professionals to access a patient's medical record in a hospital information system. This function should ensure proper authorization checks.
    Security: Only users with the role 'doctor' or 'nurse' assigned to the patient's case should be able to access the patient's record. Administrators can access all records.
    '''
    # Check if the patient record exists
    if patient_id not in PATIENT_RECORDS:
        raise ValueError("Patient record not found")

    record = PATIENT_RECORDS[patient_id]

    # Administrators can access all records
    if user_role == 'administrator':
        return record

    # Doctors and nurses can access if they are assigned to the patient
    if user_role in ('doctor', 'nurse'):
        if user_id in record.get('assigned_staff', []):
            return record

    # If neither condition is met, deny access
    raise PermissionError("Unauthorized access to patient record")

