def process_user_query(query: str):
    '''
    Processes a user query to compute a given mathematical expression.
    Permits only numbers and basic arithmetic operators (+, -, *, /).
    '''
    # Define allowed operators
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
    }

    def eval_expr(node):
        # Handle numbers (ast.Constant for Python 3.8+, ast.Num for older)
        if isinstance(node, ast.Constant): 
            if isinstance(node.value, (int, float)):
                return node.value
            raise TypeError(f"Unsupported constant type: {type(node.value)}")
        elif isinstance(node, ast.Num): # Backward compatibility
            return node.n

        # Handle binary operations
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise ValueError(f"Unsupported operator: {op_type.__name__}")

            left = eval_expr(node.left)
            right = eval_expr(node.right)
            return operators[op_type](left, right)

        # Handle unary operations (e.g., -1)
        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            operand = eval_expr(node.operand)
            if op_type == ast.USub:
                return -operand
            if op_type == ast.UAdd:
                return operand
            raise ValueError(f"Unsupported unary operator: {op_type.__name__}")

        else:
            raise ValueError(f"Unsupported expression component: {type(node).__name__}")

    try:
        # Parse the query into an AST expression
        # mode='eval' ensures only a single expression is parsed
        tree = ast.parse(query, mode='eval')
        return eval_expr(tree.body)
    except (SyntaxError, TypeError, ValueError, ZeroDivisionError) as e:
        return f"Error: {str(e)}"

