        ast.Div: operator.truediv,
    }

    # Define supported unary operators
    un_ops = {
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def evaluate(node):
        # Handle numbers (ast.Constant is used in Python 3.8+, replaces ast.Num)
        if isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)):
                return node.value
            raise TypeError(f"Unsupported constant type: {type(node.value)}")

        # Handle binary operations (+, -, *, /)
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type in bin_ops:
                left = evaluate(node.left)
                right = evaluate(node.right)
                return bin_ops[op_type](left, right)
            raise ValueError(f"Unsupported binary operator: {op_type.__name__}")

        # Handle unary operations (e.g., -5, +5)
        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type in un_ops:
                operand = evaluate(node.operand)
                return un_ops[op_type](operand)
            raise ValueError(f"Unsupported unary operator: {op_type.__name__}")

        else:
            raise ValueError(f"Unsupported expression component: {type(node).__name__}")

    try:
        # Parse the expression into an AST. mode='eval' ensures it's a single expression.
        tree = ast.parse(expression, mode='eval')
        # The root of the tree is an ast.Expression object; its body is the actual expression.
        return evaluate(tree.body)
    except (SyntaxError, ZeroDivisionError, TypeError, ValueError) as e:
        # Re-raise or handle the error as needed.
        raise e

