    Safely evaluates simple arithmetic and string operations from a user-provided string.
    Avoids the use of eval() or exec() to prevent code execution vulnerabilities.
    """
    # Define allowed binary operators
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
    }

    # Define allowed unary operators
    unary_operators = {
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def evaluate(node):
        if isinstance(node, ast.Constant):
            return node.value

        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Operator {op_type.__name__} is not supported.")

            left = evaluate(node.left)
            right = evaluate(node.right)
            return operators[op_type](left, right)

        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in unary_operators:
                raise TypeError(f"Unary operator {op_type.__name__} is not supported.")

            operand = evaluate(node.operand)
            return unary_operators[op_type](operand)

        else:
            raise TypeError(f"Unsupported expression node: {type(node).__name__}")

    try:
        # Parse the input string into an AST expression
        # mode='eval' ensures that only a single expression is parsed, not statements
        tree = ast.parse(script_str.strip(), mode='eval')
